patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
index 61e93e0398be7..d9e9c25b4fb45 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
@@ -3389,7 +3389,7 @@ bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
   Type *VTy = V->getType();

   if (DemandedMask == fcNone) {
-    if (isa<UndefValue>(V))
+    if (isa<PoisonValue>(V))
       return false;
     replaceUse(U, PoisonValue::get(VTy));
     return true;
@@ -3403,7 +3403,7 @@ bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
     Known.knownNot(~DemandedMask);

     if (Known.KnownFPClasses == fcNone) {
-      if (isa<UndefValue>(V))
+      if (isa<PoisonValue>(V))
         return false;
       replaceUse(U, PoisonValue::get(VTy));
       return true;

tests.test_body:
define nofpclass(all) float @ret_nofpclass_all_undef() {
  ret float undef
}

; Function Attrs: nocallback nofree nosync nounwind speculatable willreturn memory(none)
declare float @llvm.arithmetic.fence.f32(float) #0

define nofpclass(nan) float @undef_folds_to_poison_arg() {
  %fence = call float @llvm.arithmetic.fence.f32(float nofpclass(inf zero sub norm) undef)
  ret float %fence
}

attributes #0 = { nocallback nofree nosync nounwind speculatable willreturn memory(none) }

define nofpclass(inf) float @ret_nofpclass_inf_undef() {
  ret float undef
}
